diff --git a/public/commander/app.js b/public/commander/app.js
new file mode 100644
index 0000000..c66cc21
--- /dev/null
+++ b/public/commander/app.js
@@ -0,0 +1,189 @@
+(() => {
+  const state = {
+    room: null,
+    status: null,
+  };
+
+  const playerNameEl = document.getElementById("playerName");
+  const cityNameEl = document.getElementById("cityName");
+  const createJoinButtonEl = document.getElementById("createJoinButton");
+  const connectionStateEl = document.getElementById("connectionState");
+  const signalFeedEl = document.getElementById("signalFeed");
+  const dispatchResultsEl = document.getElementById("dispatchResults");
+  const assetStatusEl = document.getElementById("assetStatus");
+  const targetIdEl = document.getElementById("targetId");
+  const cityBaseHpEl = document.getElementById("cityBaseHp");
+  const commanderScoreEl = document.getElementById("commanderScore");
+  const activeBarriersEl = document.getElementById("activeBarriers");
+  const selectedTargetEl = document.getElementById("selectedTarget");
+
+  function updateConnectionState(text, className) {
+    connectionStateEl.textContent = text;
+    connectionStateEl.className = `status ${className || ""}`.trim();
+  }
+
+  function appendSignal(entry) {
+    const li = document.createElement("li");
+    li.className = entry.severity || "nominal";
+    const dispatchSuffix = entry.dispatchId ? ` [${entry.dispatchId}]` : "";
+    li.textContent = `${new Date(entry.timestamp).toLocaleTimeString()} :: ${entry.message}${dispatchSuffix}`;
+    signalFeedEl.prepend(li);
+    if (signalFeedEl.children.length > 40) {
+      signalFeedEl.removeChild(signalFeedEl.lastChild);
+    }
+  }
+
+  function appendDispatchResult(entry) {
+    const li = document.createElement("li");
+    li.className = entry.outcome === "FAILED" ? "critical" : entry.outcome === "PARTIAL" ? "alert" : "nominal";
+    li.textContent = `${entry.assetName} -> ${entry.targetId} :: ${entry.outcome}`;
+    dispatchResultsEl.prepend(li);
+    if (dispatchResultsEl.children.length > 30) {
+      dispatchResultsEl.removeChild(dispatchResultsEl.lastChild);
+    }
+  }
+
+  function renderCommanderStatus(payload) {
+    state.status = payload;
+    cityBaseHpEl.textContent = String(payload.cityBaseHp);
+    commanderScoreEl.textContent = String(payload.commanderScore);
+    activeBarriersEl.textContent = String(payload.activeBarriers);
+    selectedTargetEl.textContent = payload.selectedLeviathanId || "NONE";
+
+    assetStatusEl.innerHTML = "";
+    Object.keys(payload.assetsRemaining).forEach((assetName) => {
+      const li = document.createElement("li");
+      const remaining = payload.assetsRemaining[assetName];
+      const cooldownMs = payload.assetCooldownsMsRemaining[assetName] || 0;
+      const isReady = payload.assetCooldownsReady ? payload.assetCooldownsReady[assetName] : cooldownMs <= 0;
+      const progress = payload.assetCooldownsProgress ? payload.assetCooldownsProgress[assetName] : isReady ? 1 : 0;
+      const progressPct = Math.round((progress || 0) * 100);
+      li.textContent = `${assetName} :: ${remaining} REMAINING :: CD ${Math.ceil(cooldownMs / 1000)}s :: ${progressPct}% :: ${isReady ? "READY" : "CHARGING"}`;
+      li.className = isReady ? "nominal" : "alert";
+      assetStatusEl.appendChild(li);
+    });
+  }
+
+  function refreshTargets() {
+    if (!state.room || !state.room.state || !state.room.state.leviathans) {
+      return;
+    }
+
+    const current = targetIdEl.value;
+    targetIdEl.innerHTML = "";
+
+    state.room.state.leviathans.forEach((leviathan) => {
+      const option = document.createElement("option");
+      option.value = leviathan.id;
+      option.textContent = `${leviathan.name} (${leviathan.status})`;
+      targetIdEl.appendChild(option);
+    });
+
+    if (current) {
+      targetIdEl.value = current;
+    }
+  }
+
+  async function loadCities() {
+    const response = await fetch("/api/matches/options");
+    const payload = await response.json();
+    cityNameEl.innerHTML = "";
+    payload.cityOptions.forEach((city) => {
+      const option = document.createElement("option");
+      option.value = city;
+      option.textContent = city;
+      cityNameEl.appendChild(option);
+    });
+    cityNameEl.value = payload.defaultCity;
+  }
+
+  async function createAndJoinAsCommander() {
+    updateConnectionState("CONNECTING", "alert");
+
+    const createResponse = await fetch("/api/matches", {
+      method: "POST",
+      headers: { "Content-Type": "application/json" },
+      body: JSON.stringify({ cityName: cityNameEl.value }),
+    });
+
+    if (!createResponse.ok) {
+      throw new Error("Failed to create match");
+    }
+
+    const reservation = await createResponse.json();
+    const endpoint = reservation.wsEndpoint.replace(/^ws:/, window.location.protocol === "https:" ? "wss:" : "ws:");
+
+    const client = new window.Colyseus.Client(endpoint);
+    const room = await client.joinById(reservation.roomId, {
+      playerName: (playerNameEl.value || "Commander").trim(),
+    });
+
+    state.room = room;
+    refreshTargets();
+
+    room.onStateChange(() => {
+      refreshTargets();
+    });
+
+    room.onMessage("signal.feed", (payload) => {
+      appendSignal(payload);
+    });
+
+    room.onMessage("commander.status", (payload) => {
+      renderCommanderStatus(payload);
+    });
+
+    room.onMessage("commander.dispatch.result", (payload) => {
+      appendDispatchResult(payload);
+    });
+
+    updateConnectionState(`ONLINE ROOM ${room.id}`, "nominal");
+  }
+
+  function sendDispatch(assetName) {
+    if (!state.room) {
+      appendSignal({
+        timestamp: Date.now(),
+        message: "NO ACTIVE ROOM. CREATE MATCH FIRST.",
+        severity: "critical",
+      });
+      return;
+    }
+
+    const targetId = targetIdEl.value || "city-base";
+    if (targetId !== "city-base") {
+      state.room.send("commander.select", { leviathanId: targetId });
+    }
+
+    state.room.send("commander.dispatch", {
+      assetName,
+      targetId,
+    });
+  }
+
+  createJoinButtonEl.addEventListener("click", async () => {
+    createJoinButtonEl.disabled = true;
+    try {
+      await createAndJoinAsCommander();
+    } catch (error) {
+      updateConnectionState("OFFLINE", "critical");
+      appendSignal({
+        timestamp: Date.now(),
+        message: `CONNECT ERROR: ${error.message}`,
+        severity: "critical",
+      });
+    } finally {
+      createJoinButtonEl.disabled = false;
+    }
+  });
+
+  document.querySelectorAll("[data-asset]").forEach((button) => {
+    button.addEventListener("click", () => {
+      sendDispatch(button.dataset.asset);
+    });
+  });
+
+  loadCities().catch(() => {
+    updateConnectionState("OFFLINE", "critical");
+  });
+})();
diff --git a/public/commander/index.html b/public/commander/index.html
new file mode 100644
index 0000000..c3b7e1f
--- /dev/null
+++ b/public/commander/index.html
@@ -0,0 +1,81 @@
+<!doctype html>
+<html lang="en">
+  <head>
+    <meta charset="UTF-8" />
+    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
+    <title>Kaiju Arcade Commander Console</title>
+    <link rel="stylesheet" href="/commander/styles.css" />
+    <script src="https://unpkg.com/colyseus.js@0.15.14/dist/colyseus.js"></script>
+  </head>
+  <body>
+    <main class="console-shell">
+      <header class="console-header">
+        <h1>COMMANDER CONSOLE</h1>
+        <p class="subline">LIVE MITIGATION CONTROL SURFACE</p>
+      </header>
+
+      <section class="panel controls-panel">
+        <h2>SESSION</h2>
+        <div class="field-row">
+          <label for="playerName">Operator</label>
+          <input id="playerName" type="text" value="Commander" maxlength="24" />
+        </div>
+        <div class="field-row">
+          <label for="cityName">City</label>
+          <select id="cityName"></select>
+        </div>
+        <button id="createJoinButton" class="primary">Create Match + Join</button>
+        <p id="connectionState" class="status">OFFLINE</p>
+      </section>
+
+      <section class="panel status-panel">
+        <h2>COMMAND STATUS</h2>
+        <div class="status-grid">
+          <div>
+            <span>BASE HP</span>
+            <strong id="cityBaseHp">-</strong>
+          </div>
+          <div>
+            <span>SCORE</span>
+            <strong id="commanderScore">-</strong>
+          </div>
+          <div>
+            <span>BARRIERS</span>
+            <strong id="activeBarriers">-</strong>
+          </div>
+          <div>
+            <span>SELECTED TARGET</span>
+            <strong id="selectedTarget">-</strong>
+          </div>
+        </div>
+      </section>
+
+      <section class="panel dispatch-panel">
+        <h2>DISPATCH</h2>
+        <div class="field-row">
+          <label for="targetId">Target</label>
+          <select id="targetId"></select>
+        </div>
+        <div class="dispatch-buttons">
+          <button data-asset="Scramble Jets">Scramble Jets</button>
+          <button data-asset="Deploy Mechs">Deploy Mechs</button>
+          <button data-asset="Raise Barrier">Raise Barrier</button>
+          <button data-asset="Evac Sector">Evac Sector</button>
+        </div>
+        <ul id="assetStatus"></ul>
+      </section>
+
+      <section class="panel feed-panel">
+        <h2>SIGNAL FEED</h2>
+        <ul id="signalFeed"></ul>
+      </section>
+
+      <section class="panel feed-panel">
+        <h2>DISPATCH RESULTS</h2>
+        <ul id="dispatchResults"></ul>
+      </section>
+    </main>
+
+    <script src="/commander/app.js"></script>
+  </body>
+</html>
diff --git a/public/commander/styles.css b/public/commander/styles.css
new file mode 100644
index 0000000..e28768c
--- /dev/null
+++ b/public/commander/styles.css
@@ -0,0 +1,166 @@
+:root {
+  --bg: #070704;
+  --panel: #111108;
+  --line: #33280d;
+  --amber: #ffb300;
+  --green: #00d86f;
+  --red: #ff4747;
+  --text: #ffd76d;
+}
+
+* {
+  box-sizing: border-box;
+}
+
+body {
+  margin: 0;
+  min-height: 100vh;
+  font-family: "Arial Narrow", "Franklin Gothic Medium", sans-serif;
+  background:
+    repeating-linear-gradient(
+      180deg,
+      rgba(255, 179, 0, 0.05) 0,
+      rgba(255, 179, 0, 0.05) 1px,
+      transparent 2px,
+      transparent 4px
+    ),
+    radial-gradient(circle at 20% 10%, #1f1a09, var(--bg));
+  color: var(--text);
+}
+
+.console-shell {
+  width: min(1200px, 96vw);
+  margin: 1rem auto;
+  display: grid;
+  grid-template-columns: repeat(2, minmax(0, 1fr));
+  gap: 0.75rem;
+}
+
+.console-header {
+  grid-column: 1 / -1;
+  border: 1px solid var(--line);
+  background: rgba(17, 17, 8, 0.92);
+  padding: 0.75rem 1rem;
+  text-transform: uppercase;
+  letter-spacing: 0.1em;
+}
+
+.console-header h1 {
+  margin: 0;
+  font-size: 1.2rem;
+  color: var(--amber);
+  text-shadow: 0 0 8px rgba(255, 179, 0, 0.5);
+}
+
+.console-header .subline {
+  margin: 0.25rem 0 0;
+  color: #bca063;
+  font-size: 0.85rem;
+}
+
+.panel {
+  border: 1px solid var(--line);
+  background: rgba(17, 17, 8, 0.92);
+  padding: 0.75rem;
+}
+
+.panel h2 {
+  margin: 0 0 0.65rem;
+  font-size: 0.85rem;
+  text-transform: uppercase;
+  color: var(--amber);
+}
+
+.field-row {
+  display: flex;
+  flex-direction: column;
+  gap: 0.25rem;
+  margin-bottom: 0.6rem;
+}
+
+input,
+select,
+button {
+  width: 100%;
+  border: 1px solid var(--line);
+  background: #0b0b05;
+  color: var(--text);
+  padding: 0.45rem 0.5rem;
+  font: inherit;
+  text-transform: uppercase;
+  letter-spacing: 0.05em;
+}
+
+button {
+  cursor: pointer;
+}
+
+button.primary {
+  border-color: var(--amber);
+}
+
+.status {
+  margin: 0.5rem 0 0;
+  font-size: 0.85rem;
+}
+
+.status-grid {
+  display: grid;
+  grid-template-columns: repeat(2, minmax(0, 1fr));
+  gap: 0.5rem;
+}
+
+.status-grid div {
+  border: 1px solid #2a2210;
+  padding: 0.5rem;
+}
+
+.status-grid span {
+  display: block;
+  font-size: 0.7rem;
+  color: #bca063;
+}
+
+.status-grid strong {
+  display: block;
+  margin-top: 0.3rem;
+  font-size: 1rem;
+}
+
+.dispatch-buttons {
+  display: grid;
+  grid-template-columns: repeat(2, minmax(0, 1fr));
+  gap: 0.45rem;
+}
+
+ul {
+  margin: 0;
+  padding: 0;
+  list-style: none;
+  max-height: 220px;
+  overflow: auto;
+}
+
+li {
+  border-bottom: 1px solid #241d0e;
+  padding: 0.35rem 0;
+  font-size: 0.78rem;
+}
+
+li.nominal {
+  color: var(--amber);
+}
+
+li.alert {
+  color: var(--green);
+}
+
+li.critical {
+  color: var(--red);
+}
+
+@media (max-width: 880px) {
+  .console-shell {
+    grid-template-columns: 1fr;
+  }
+}
diff --git a/src/game/GameLoop.test.ts b/src/game/GameLoop.test.ts
index 9f65778..6fa94ea 100644
--- a/src/game/GameLoop.test.ts
+++ b/src/game/GameLoop.test.ts
@@ -50,4 +50,33 @@ describe("GameLoop determinism", () => {
     expect(validateTickTiming(180).isValid).toBe(true);
     expect(validateTickTiming(230).isValid).toBe(false);
   });
+
+  it("resolves pending dispatches when delay elapses", () => {
+    const state = buildState();
+    const target = state.leviathans[0];
+    target.hp = 100;
+
+    const dispatch = state.createDispatchRecord("Deploy Mechs", target.id, 1_000);
+    dispatch.delayMs = 0;
+    state.dispatchHistory.push(dispatch);
+
+    executeTick({ state, deltaMs: 200, tickCount: 1, now: 1_200 });
+
+    expect(state.dispatchHistory[0].resolvedAt).toBe(1_200);
+    expect(["SUCCESS", "PARTIAL", "FAILED", "UNVERIFIED"]).toContain(state.dispatchHistory[0].outcome);
+    expect(state.signalFeed.length).toBeGreaterThan(0);
+  });
+
+  it("creates barrier when Raise Barrier dispatch resolves", () => {
+    const state = buildState();
+    const dispatch = state.createDispatchRecord("Raise Barrier", "city-base", 2_000);
+    dispatch.delayMs = 0;
+    state.dispatchHistory.push(dispatch);
+
+    executeTick({ state, deltaMs: 200, tickCount: 2, now: 2_200 });
+
+    expect(state.dispatchHistory[0].outcome).toBe("SUCCESS");
+    expect(state.activeBarriers.length).toBe(1);
+    expect(state.activeBarriers[0].expiresAt).toBe(10_200);
+  });
 });
diff --git a/src/game/GameLoop.ts b/src/game/GameLoop.ts
index 2e2fe7b..4712e4e 100644
--- a/src/game/GameLoop.ts
+++ b/src/game/GameLoop.ts
@@ -30,6 +30,7 @@ export function executeTick(context: GameLoopContext): void {

   updateLeviathanPositions(context);
   processAttacks(context);
+  resolveCommanderDispatches(context);
   updateStatusEffects(context);
   checkWinConditions(context);
 }
@@ -115,8 +116,98 @@ function processAttacks(context: GameLoopContext): void {
     }
   }

-  // Process Commander dispatch queue and mitigation
-  // TODO: Implement asset dispatch resolution with delay
+}
+
+function resolveCommanderDispatches(context: GameLoopContext): void {
+  const { state, now } = context;
+
+  for (const dispatch of state.dispatchHistory) {
+    if (dispatch.resolvedAt > 0) {
+      continue;
+    }
+
+    const isReadyToResolve = now - dispatch.dispatchedAt >= dispatch.delayMs;
+    if (!isReadyToResolve) {
+      continue;
+    }
+
+    dispatch.resolvedAt = now;
+
+    switch (dispatch.assetName) {
+      case "Scramble Jets":
+      case "Deploy Mechs": {
+        const target = state.getLeviathan(dispatch.targetId);
+        if (!target || target.status === "CONTAINED") {
+          dispatch.outcome = "UNVERIFIED";
+          state.addSignal(
+            `MITIGATION UNVERIFIED - ${dispatch.assetName} TARGET LOST`,
+            "alert",
+            "SYSTEM",
+            dispatch.id
+          );
+          break;
+        }
+
+        const roll = deterministicRoll(dispatch.id, now);
+        const profile = dispatch.assetName === "Scramble Jets"
+          ? { success: 0.65, partial: 0.2, maxDamage: 40 }
+          : { success: 0.55, partial: 0.25, maxDamage: 30 };
+
+        if (roll <= profile.success) {
+          dispatch.outcome = "SUCCESS";
+          applyMitigationDamage(state, target.id, profile.maxDamage, now, dispatch.id);
+          state.metadata.commanderScore += 20;
+          state.addSignal(
+            `${dispatch.assetName.toUpperCase()} SUCCESS - ${target.name} CONTAINMENT HIT`,
+            "nominal",
+            "SYSTEM",
+            dispatch.id
+          );
+        } else if (roll <= profile.success + profile.partial) {
+          dispatch.outcome = "PARTIAL";
+          applyMitigationDamage(state, target.id, Math.round(profile.maxDamage * 0.5), now, dispatch.id);
+          state.metadata.commanderScore += 8;
+          state.addSignal(
+            `${dispatch.assetName.toUpperCase()} PARTIAL - ${target.name} REPULSED`,
+            "alert",
+            "SYSTEM",
+            dispatch.id
+          );
+        } else {
+          dispatch.outcome = "FAILED";
+          state.addSignal(
+            `${dispatch.assetName.toUpperCase()} FAILED - ${target.name} EVADED`,
+            "critical",
+            "SYSTEM",
+            dispatch.id
+          );
+        }
+
+        break;
+      }
+
+      case "Raise Barrier": {
+        const barrier = state.createBarrier(now, now + 8_000);
+        state.activeBarriers.push(barrier);
+        dispatch.outcome = "SUCCESS";
+        state.metadata.commanderScore += 5;
+        state.addSignal("RAISE BARRIER ONLINE - CITY BASE SHIELDED", "nominal", "SYSTEM", dispatch.id);
+        break;
+      }
+
+      case "Evac Sector": {
+        dispatch.outcome = "SUCCESS";
+        state.metadata.commanderScore += 12;
+        state.addSignal("EVAC SECTOR SUCCESS - CIVILIANS RELOCATED", "nominal", "SYSTEM", dispatch.id);
+        break;
+      }
+
+      default:
+        dispatch.outcome = "UNVERIFIED";
+        state.addSignal("MITIGATION UNVERIFIED - UNKNOWN ASSET", "alert", "SYSTEM", dispatch.id);
+        break;
+    }
+  }
 }

 /**
@@ -147,6 +238,40 @@ function updateStatusEffects(context: GameLoopContext): void {
   }
 }

+function applyMitigationDamage(
+  state: MatchSchema,
+  targetId: string,
+  damage: number,
+  now: number,
+  dispatchId: string
+): void {
+  const target = state.getLeviathan(targetId);
+  if (!target || target.status === "CONTAINED") {
+    return;
+  }
+
+  target.hp = Math.max(0, target.hp - damage);
+  target.damageReceived += damage;
+
+  if (target.hp <= 0) {
+    target.status = "CONTAINED";
+    target.statusEndTime = now;
+    state.addSignal(`KAIJU ${target.name} CONTAINED`, "nominal", "SYSTEM", dispatchId);
+  }
+}
+
+function deterministicRoll(seed: string, now: number): number {
+  const input = `${seed}:${Math.floor(now / GAME_CONSTANTS.TICK_MS)}`;
+  let hash = 2166136261;
+
+  for (let i = 0; i < input.length; i++) {
+    hash ^= input.charCodeAt(i);
+    hash = Math.imul(hash, 16777619);
+  }
+
+  return ((hash >>> 0) % 1000) / 1000;
+}
+
 /**
  * Check for match win/loss conditions
  */
diff --git a/src/game/MatchRoom.test.ts b/src/game/MatchRoom.test.ts
index 02f4188..dc3c4b0 100644
--- a/src/game/MatchRoom.test.ts
+++ b/src/game/MatchRoom.test.ts
@@ -225,6 +225,182 @@ describe("MatchRoom role assignment", () => {
     room.onDispose();
   });

+  it("broadcasts signal feed events for commander and kaiju joins", () => {
+    const room = new MatchRoom();
+    const broadcast = jest.fn();
+    (room as unknown as { broadcast: typeof broadcast }).broadcast = broadcast;
+
+    room.onCreate({ cityName: "Neo Tokyo" });
+    room.onJoin(
+      { id: "client-1", sessionId: "session-1" } as unknown as never,
+      { playerName: "Commander One" }
+    );
+    room.onJoin(
+      { id: "client-2", sessionId: "session-2" } as unknown as never,
+      { playerName: "Kaiju One" }
+    );
+
+    expect(broadcast).toHaveBeenCalledWith(
+      "signal.feed",
+      expect.objectContaining({
+        type: "signal.feed",
+        message: "COMMANDER COMMANDER ONE ONLINE",
+        severity: "nominal",
+      })
+    );
+    expect(broadcast).toHaveBeenCalledWith(
+      "signal.feed",
+      expect.objectContaining({
+        type: "signal.feed",
+        message: expect.stringContaining("PILOT ENGAGED"),
+        severity: "nominal",
+      })
+    );
+
+    room.onDispose();
+  });
+
+  it("validates commander dispatch target and cooldown before consuming assets", () => {
+    const room = new MatchRoom();
+
+    room.onCreate({ cityName: "Neo Tokyo" });
+    room.onJoin(
+      { id: "client-1", sessionId: "session-1" } as unknown as never,
+      { playerName: "Commander One" }
+    );
+    room.onJoin(
+      { id: "client-2", sessionId: "session-2" } as unknown as never,
+      { playerName: "Kaiju One" }
+    );
+
+    const targetLeviathan = room.state.leviathans.find(
+      (leviathan: LeviathanSchema) => leviathan.playerId === "session-2"
+    );
+    expect(targetLeviathan).toBeDefined();
+
+    const initialJetCount = room.state.commander.assetsRemaining.get("Scramble Jets");
+
+    (room as unknown as {
+      handleCommanderDispatch: (assetName: string, targetId: string) => void;
+    }).handleCommanderDispatch("Scramble Jets", "missing-target");
+
+    expect(room.state.commander.assetsRemaining.get("Scramble Jets")).toBe(initialJetCount);
+    expect(
+      room.state.signalFeed.some(
+        (signal: { message: string }) => signal.message === "DISPATCH FAILED: Scramble Jets TARGET INVALID"
+      )
+    ).toBe(true);
+
+    (room as unknown as {
+      handleCommanderDispatch: (assetName: string, targetId: string) => void;
+    }).handleCommanderDispatch("Scramble Jets", targetLeviathan?.id ?? "");
+
